function jsonArray(value) {
  return Array.isArray(value) ? value : [];
}

function appControlText(value, keys) {
  for (const key of keys) {
    const text = value?.[key];
    if (typeof text === "string" && text.trim()) {
      return text.trim();
    }
  }
  return "";
}

function appControlBoolean(value, keys) {
  for (const key of keys) {
    const candidate = value?.[key];
    if (typeof candidate === "boolean") return candidate;
    if (typeof candidate === "string") {
      const normalized = candidate.trim().toLowerCase();
      if (["1", "true", "yes", "on"].includes(normalized)) return true;
      if (["0", "false", "no", "off"].includes(normalized)) return false;
    }
  }
  return false;
}

function normalizeAppControlWebhookAuthMode(value) {
  const raw = String(value || "").trim().toLowerCase();
  if (!raw) return "";
  if (["signed", "signed_hmac", "hmac", "stripe", "stripe_compatible"].includes(raw)) {
    return "signed_hmac";
  }
  if (["public", "public_token", "bearer", "bearer_path", "url_token"].includes(raw)) {
    return "public_token";
  }
  return "";
}

function appControlLoopspaceTriggerPayload(value) {
  const candidates = [
    value?.payload,
    value?.sync,
    value?.response,
    value?.data,
    value?.event,
    value,
  ].filter(Boolean);
  for (const candidate of candidates) {
    if (
      Array.isArray(candidate?.triggers) || Array.isArray(candidate?.loopspace_triggers) || Array.isArray(candidate?.runs) || Array.isArray(candidate?.logs) || Array.isArray(candidate?.trigger_runs)
    ) {
      return candidate;
    }
  }
  return value || {};
}

function appControlLoopspaceTriggerRows(value) {
  const payload = appControlLoopspaceTriggerPayload(value);
  const rows = payload?.triggers || payload?.loopspace_triggers || [];
  return Array.isArray(rows)
    ? rows.map((row) => {
      const loopspaceIds = Array.isArray(row?.loopspace_ids)
        ? row.loopspace_ids
        : Array.isArray(row?.loopspaceIds)
          ? row.loopspaceIds
          : [];
      const config = row?.config && typeof row.config === "object" ? row.config : {};
      const id = appControlText(row, ["id", "trigger_id"]);
      const type = appControlText(row, ["type", "trigger_type"]).toLowerCase() || "cron";
      const webhookAuthMode = normalizeAppControlWebhookAuthMode(
        appControlText(row, ["webhook_auth_mode"])
        || appControlText(config, ["webhook_auth_mode"]),
      );
      return {
        ...row,
        config,
        enabled: row?.enabled !== false,
        id,
        last_run_at_ms: Number(row?.last_run_at_ms || 0) || 0,
        last_status: appControlText(row, ["last_status"]),
        loopspace_ids: loopspaceIds.map((item) => String(item || "").trim()).filter(Boolean),
        name: appControlText(row, ["name", "trigger_name"]) || id,
        next_due_at_ms: Number(row?.next_due_at_ms || 0) || 0,
        type,
        webhook_auth_mode: type === "webhook" ? webhookAuthMode || "signed_hmac" : "",
        webhook_path: appControlText(row, ["webhook_path"]) || appControlText(config, ["webhook_path"]),
        webhook_secret_hint: appControlText(row, ["webhook_secret_hint"]),
        webhook_signature_tolerance_sec: Number(row?.webhook_signature_tolerance_sec || 300) || 300,
      };
    }).filter((row) => row.id)
    : [];
}

function appControlLoopspaceTriggerRunRows(value) {
  const payload = appControlLoopspaceTriggerPayload(value);
  const rows = payload?.logs || payload?.runs || payload?.trigger_runs || [];
  return Array.isArray(rows)
    ? rows.map((row) => {
      const loopspaceIds = Array.isArray(row?.loopspace_ids)
        ? row.loopspace_ids
        : Array.isArray(row?.loopspaceIds)
          ? row.loopspaceIds
          : [];
      return {
        ...row,
        completed_at_ms: Number(row?.completed_at_ms || 0) || 0,
        created_at_ms: Number(row?.created_at_ms || 0) || 0,
        error: appControlText(row, ["error"]),
        id: appControlText(row, ["id", "run_id"]),
        loopspace_ids: loopspaceIds.map((item) => String(item || "").trim()).filter(Boolean),
        status: appControlText(row, ["status"]) || "run",
        trigger_id: appControlText(row, ["trigger_id"]),
        type: appControlText(row, ["type", "trigger_type"]).toLowerCase(),
      };
    }).filter((row) => row.id)
    : [];
}

function filterLoopspaceRuntimeEvents(events, loopspaceId) {
  const target = String(loopspaceId || "").trim();
  if (!target) return events || [];
  return (events || []).filter((event) => (
    !event?.loopspace_id || event.loopspace_id === target
  ));
}

function appControlLoopspaceRuntimeEventRows(value, loopspaceId = "") {
  const targetLoopspaceId = String(loopspaceId || "").trim();
  const candidates = [
    value?.payload,
    value?.sync,
    value?.response,
    value?.data,
    value?.event,
    value?.applied_payload,
    value,
  ].filter(Boolean);
  const rows = [];
  const pushEventRows = (items, parentLoopspaceId = "") => {
    const parentId = String(parentLoopspaceId || "").trim();
    if (targetLoopspaceId && parentId && parentId !== targetLoopspaceId) return;
    if (!Array.isArray(items)) return;
    for (const item of items) {
      if (!item || typeof item !== "object") continue;
      const eventLoopspaceId = appControlText(item, ["loopspace_id"]);
      if (targetLoopspaceId && eventLoopspaceId && eventLoopspaceId !== targetLoopspaceId) continue;
      rows.push(parentId && !eventLoopspaceId
        ? {
          ...item,
          loopspace_id: parentId,
        }
        : item);
    }
  };
  for (const candidate of candidates) {
    for (const key of ["runtime_events", "events"]) {
      pushEventRows(candidate?.[key]);
    }
    const loopspaces = Array.isArray(candidate?.loopspaces) ? candidate.loopspaces : [];
    for (const loopspaceRow of loopspaces) {
      const parentLoopspaceId = appControlText(loopspaceRow, ["id", "loopspace_id"]);
      for (const key of ["runtime_events", "events"]) {
        pushEventRows(loopspaceRow?.[key], parentLoopspaceId);
      }
    }
    const loopspaceRow = candidate?.loopspace && typeof candidate.loopspace === "object"
      ? candidate.loopspace
      : null;
    if (loopspaceRow) {
      const parentLoopspaceId = appControlText(loopspaceRow, ["id", "loopspace_id"]);
      for (const key of ["runtime_events", "events"]) {
        pushEventRows(loopspaceRow?.[key], parentLoopspaceId);
      }
    }
  }
  const byId = new Map();
  for (const row of rows) {
    const id = appControlText(row, ["id", "event_id"]);
    if (!id) continue;
    const details = row?.details && typeof row.details === "object"
      ? row.details
      : row?.details_json && typeof row.details_json === "object"
        ? row.details_json
        : {};
      const normalized = {
        ...row,
        created_at_ms: Number(row?.created_at_ms || 0) || 0,
        details,
        edge_id: appControlText(row, ["edge_id", "loop_runtime_edge_id"])
          || appControlText(details, ["edge_id", "loop_runtime_edge_id"]),
        event_seq: Number(row?.event_seq || row?.seq || 0) || 0,
        id,
        kind: appControlText(row, ["kind", "event_kind"]) || "runtime.event",
        loopspace_id: appControlText(row, ["loopspace_id"])
          || appControlText(details, ["loopspace_id"]),
        message: appControlText(row, ["message"]) || appControlText(row, ["status"]) || "Runtime event",
        node_id: appControlText(row, ["node_id", "loop_runtime_node_id"])
          || appControlText(details, ["node_id", "loop_runtime_node_id"]),
        run_id: appControlText(row, ["run_id", "loop_runtime_run_id"])
          || appControlText(details, ["run_id", "loop_runtime_run_id"]),
        severity: appControlText(row, ["severity"]).toLowerCase() || "info",
        status: appControlText(row, ["status"]) || appControlText(details, ["status", "state", "parent_status"]),
        trigger_id: appControlText(row, ["trigger_id"])
          || appControlText(details, ["trigger_id"]),
        trigger_run_id: appControlText(row, ["trigger_run_id"])
          || appControlText(details, ["trigger_run_id"]),
      };
    if (targetLoopspaceId && normalized.loopspace_id !== targetLoopspaceId) {
      continue;
    }
    byId.set(id, { ...(byId.get(id) || {}), ...normalized });
  }
  return [...byId.values()].sort((left, right) => (
    (left.event_seq || 0) - (right.event_seq || 0)
    || (left.created_at_ms || 0) - (right.created_at_ms || 0)
    || String(left.id).localeCompare(String(right.id))
  ));
}

function appControlLoopspaceRuntimeEventPage(value, loopspaceId = "") {
  const targetLoopspaceId = String(loopspaceId || "").trim();
  const candidates = [
    value?.payload,
    value?.sync,
    value?.response,
    value?.data,
    value?.event,
    value?.applied_payload,
    value,
  ].filter(Boolean);
  const normalizePage = (page) => page && typeof page === "object"
    ? {
      before_event_seq: Number(page.before_event_seq || 0) || 0,
      has_more_before: Boolean(page.has_more_before),
    }
    : null;
  if (targetLoopspaceId) {
    for (const candidate of candidates) {
      const loopspaces = Array.isArray(candidate?.loopspaces) ? candidate.loopspaces : [];
      for (const loopspaceRow of loopspaces) {
        const rowLoopspaceId = appControlText(loopspaceRow, ["id", "loopspace_id"]);
        if (rowLoopspaceId !== targetLoopspaceId) continue;
        const page = normalizePage(loopspaceRow.runtime_event_page);
        if (page) return page;
      }
      const loopspaceRow = candidate?.loopspace && typeof candidate.loopspace === "object"
        ? candidate.loopspace
        : null;
      if (loopspaceRow) {
        const rowLoopspaceId = appControlText(loopspaceRow, ["id", "loopspace_id"]);
        if (!rowLoopspaceId || rowLoopspaceId === targetLoopspaceId) {
          const page = normalizePage(loopspaceRow.runtime_event_page);
          if (page) return page;
        }
      }
    }
  }
  for (const candidate of candidates) {
    const page = normalizePage(candidate?.runtime_event_page);
    if (page) return page;
  }
  const direct = candidates.find((candidate) => (
    candidate?.has_more_before !== undefined
  ));
  return {
    before_event_seq: 0,
    has_more_before: Boolean(direct?.has_more_before),
  };
}

function mergeLoopspaceRuntimeEventRows(existing, incoming, replace = false) {
  const byId = new Map();
  if (!replace) {
    for (const row of existing || []) {
      if (row?.id) byId.set(row.id, row);
    }
  }
  for (const row of incoming || []) {
    if (row?.id) byId.set(row.id, { ...(byId.get(row.id) || {}), ...row });
  }
  return [...byId.values()].sort((left, right) => (
    (left.event_seq || 0) - (right.event_seq || 0)
    || (left.created_at_ms || 0) - (right.created_at_ms || 0)
    || String(left.id).localeCompare(String(right.id))
  ));
}

function loopspaceRuntimeEventTone(event) {
  const severity = String(event?.severity || "").toLowerCase();
  const status = String(event?.status || "").toLowerCase();
  if (["error", "failed", "failure", "interrupted", "cancelled", "canceled", "aborted"].some((item) => severity === item || status === item)) return "error";
  if (["warn", "warning", "blocked", "awaiting_device"].some((item) => severity === item || status === item)) return "queued";
  if (["good", "success", "succeeded", "completed", "complete"].some((item) => severity === item || status === item)) return "good";
  if (["running", "queued", "dispatched"].includes(status)) return "active";
  return "neutral";
}

function loopspaceRuntimeEventTimelineIcon(event) {
  const status = normalizeLoopspaceNodeRuntimeStatus(loopspaceRuntimeEventStatus(event));
  const severity = String(event?.severity || "").trim().toLowerCase();
  const haystack = [
    status,
    severity,
    event?.status,
    event?.kind,
    event?.event_kind,
    event?.message,
  ].join(" ").toLowerCase();
  if (/\b(cancelled|canceled|aborted)\b/.test(haystack)) return "cancelled";
  if (status === "success" || /\b(completed|complete|success|succeeded)\b/.test(haystack)) return "completed";
  if (status === "failed" || /\b(failed|failure|error|denied)\b/.test(haystack)) return "failed";
  if (status === "resume_ready" || /\b(resume_ready|resume ready|resumable)\b/.test(haystack)) return "resume-ready";
  if (status === "interrupted" || /\b(interrupted|interrupt|timed out|timeout)\b/.test(haystack)) return "interrupted";
  if (status === "queued" || /\b(queued|queue|pending|waiting)\b/.test(haystack)) return "queued";
  if (status === "resume_requested" || /\b(resuming|resume requested|resume_requested)\b/.test(haystack)) return "resuming";
  if (status === "running" || /\b(running|dispatch|sent|started|active|processing)\b/.test(haystack)) return "running";
  return "neutral";
}

function loopspaceRuntimeLogIcon(event) {
  const status = normalizeLoopspaceNodeRuntimeStatus(loopspaceRuntimeEventStatus(event));
  const severity = String(event?.severity || "").trim().toLowerCase();
  const haystack = [
    status,
    severity,
    event?.status,
    event?.kind,
    event?.event_kind,
    event?.message,
  ].join(" ").toLowerCase();
  if (status === "success" || /\b(completed|complete|success|succeeded)\b/.test(haystack)) return "completed";
  if (/\b(cancelled|canceled|aborted)\b/.test(haystack)) return "cancelled";
  if (status === "failed" || /\b(failed|failure|error|denied)\b/.test(haystack)) return "failed";
  if (status === "interrupted" || status === "resume_ready" || /\b(interrupted|interrupt|resume_ready|resume ready)\b/.test(haystack)) return "interrupted";
  if (/\b(sent|send|dispatch sent|dispatched)\b/.test(haystack)) return "sent";
  if (/\b(trigger|manual|webhook|cron|followed|branch)\b/.test(haystack)) return "trigger";
  if (status === "queued" || /\b(queued|queue|pending|waiting)\b/.test(haystack)) return "queued";
  if (status === "running" || status === "resume_requested" || /\b(running|run|started|active|processing)\b/.test(haystack)) return "running";
  return "neutral";
}

function loopspaceRuntimeTimelineIconForStatus(status) {
  const normalized = normalizeLoopspaceNodeRuntimeStatus(status);
  if (normalized === "success") return "completed";
  if (normalized === "failed") return "failed";
  if (normalized === "interrupted") return "interrupted";
  if (normalized === "resume_ready") return "resume-ready";
  if (normalized === "queued") return "queued";
  if (normalized === "resume_requested") return "resuming";
  if (normalized === "running") return "running";
  return "neutral";
}

function loopspaceRuntimeNodeKindLabel(node = null, trigger = null) {
  if (trigger || node?.trigger_id) {
    return loopspaceTriggerTypeLabel(String(trigger?.type || node?.trigger_type || "manual").trim().toLowerCase());
  }
  switch (String(node?.node_kind || node?.kind || "").trim()) {
    case "send_message":
      return "Send message";
    case "notify_device":
      return "Notify device";
    case "run_script":
      return "Run script";
    case "document_read":
      return "Document read";
    case "document_write":
      return "Document write";
    case "asset_read":
      return "Asset read";
    case "asset_write":
      return "Asset write";
    case "device":
      return "Device";
    default:
      return String(node?.role || node?.node_kind || node?.kind || "Loop runtime").replace(/_/g, " ");
  }
}

function loopspaceRuntimeNodeTitle(node = null, trigger = null) {
  const kindLabel = loopspaceRuntimeNodeKindLabel(node, trigger);
  if (!node) return kindLabel;
  if (trigger?.name) return String(trigger.name).trim();
  if (node.node_kind === "run_script") {
    return String(
      node.label
        || loopspaceGraphPropValue(node.props, ["script_name", "name"])
        || kindLabel,
    ).trim();
  }
  if (node.node_kind === "send_message") {
    return String(node.label || kindLabel).trim();
  }
  return String(node.label || kindLabel).trim();
}

function loopspaceRuntimeStatusSentence(title, status) {
  const safeTitle = String(title || "Loop runtime").trim();
  switch (normalizeLoopspaceNodeRuntimeStatus(status)) {
    case "queued":
      return `${safeTitle} is queued.`;
    case "running":
      return `${safeTitle} is running.`;
    case "success":
      return `${safeTitle} completed.`;
    case "failed":
      return `${safeTitle} failed.`;
    case "interrupted":
      return `${safeTitle} was interrupted.`;
    case "resume_ready":
      return `${safeTitle} is ready to resume.`;
    case "resume_requested":
      return `${safeTitle} is resuming.`;
    default:
      return `${safeTitle} updated.`;
  }
}

function loopspaceRuntimeFriendlyMessage(event, title, status) {
  const fallback = loopspaceRuntimeStatusSentence(title, status);
  const message = String(event?.message || event?.status || "").trim();
  if (!message) return fallback;
  const replacements = [
    loopspaceRuntimeEventNodeId(event),
    loopspaceRuntimeEventRunId(event),
    loopspaceRuntimeEventEdgeId(event),
  ].filter(Boolean);
  let cleaned = message;
  replacements.forEach((token) => {
    cleaned = cleaned.split(token).join(title || "Loop runtime");
  });
  return cleaned.trim() || fallback;
}

function formatLoopspaceRuntimeConsoleTime(value) {
  const ms = Number(value || 0);
  if (!Number.isFinite(ms) || ms <= 0) return "--:--:--";
  try {
    return new Date(ms).toLocaleTimeString([], {
      hour: "2-digit",
      minute: "2-digit",
      second: "2-digit",
    });
  } catch {
    return "--:--:--";
  }
}

function loopspaceTriggerTypeLabel(type) {
  if (type === "webhook") return "Webhook";
  if (type === "manual") return "Manual";
  return "Cron";
}

function loopspaceTriggerTypeIcon(type) {
  if (type === "webhook") return Webhook;
  if (type === "manual") return AdsClick;
  return Schedule;
}

function formatLoopspaceRuntimeTime(value) {
  const ms = Number(value || 0);
  if (!Number.isFinite(ms) || ms <= 0) return "";
  try {
    return new Date(ms).toLocaleString([], {
      day: "numeric",
      hour: "2-digit",
      minute: "2-digit",
      month: "short",
    });
  } catch {
    return "";
  }
}

function formatLoopspaceCountdown(targetMs, nowMs = Date.now()) {
  const target = Number(targetMs || 0);
  const now = Number(nowMs || 0);
  if (!Number.isFinite(target) || target <= 0 || !Number.isFinite(now) || now <= 0) {
    return "";
  }
  const remainingMs = Math.max(0, target - now);
  if (remainingMs <= 1000) return "due now";
  const totalSeconds = Math.ceil(remainingMs / 1000);
  const days = Math.floor(totalSeconds / 86400);
  const hours = Math.floor((totalSeconds % 86400) / 3600);
  const minutes = Math.floor((totalSeconds % 3600) / 60);
  const seconds = totalSeconds % 60;
  if (days > 0) return `${days}d ${hours}h`;
  if (hours > 0) return `${hours}h ${minutes}m`;
  if (minutes > 0) return `${minutes}m ${seconds}s`;
  return `${seconds}s`;
}

function loopspaceRuntimeField(row, keys, fallback = "") {
  return appControlText(row, keys) || fallback;
}

function normalizeLoopspaceNodeRuntimeStatus(status) {
  const normalized = String(status || "").trim().toLowerCase().replace(/[\s.-]+/g, "_");
  if (!normalized) return "";
  if (["complete", "completed", "done", "success", "succeeded"].includes(normalized)) return "success";
  if (["failed", "failure", "error", "blocked"].includes(normalized)) return "failed";
  if (["resume_ready", "ready_to_resume", "resumable", "interrupted_resumable"].includes(normalized)) return "resume_ready";
  if (["resume_requested", "resuming", "resumed"].includes(normalized)) return "resume_requested";
  if (["interrupted", "interrupt", "cancelled", "canceled", "timed_out", "timeout", "aborted"].includes(normalized)) return "interrupted";
  if (["queued", "pending", "awaiting_device", "waiting"].includes(normalized)) return "queued";
  if (["active", "compacting", "compaction", "dispatching", "processing", "running", "started", "submitted", "thinking", "working"].includes(normalized)) return "running";
  return "";
}

function loopspaceNodeRuntimeStatusLabel(status) {
  switch (normalizeLoopspaceNodeRuntimeStatus(status)) {
    case "queued":
      return "Queued";
    case "running":
      return "Running";
    case "success":
      return "Success";
    case "failed":
      return "Failed";
    case "interrupted":
      return "Interrupted";
    case "resume_ready":
      return "Resume ready";
    case "resume_requested":
      return "Resuming";
    default:
      return "";
  }
}

function loopspaceNodeRuntimeStatusTone(status) {
  const normalized = normalizeLoopspaceNodeRuntimeStatus(status);
  if (normalized === "success") return "good";
  if (normalized === "failed") return "error";
  if (normalized === "interrupted" || normalized === "resume_ready") return "paused";
  if (normalized === "queued") return "queued";
  if (normalized === "running" || normalized === "resume_requested") return "active";
  return "neutral";
}

function loopspaceRuntimeEventNodeId(event) {
  return loopspaceRuntimeField(event, [
    "node_id",
    "loop_runtime_node_id",
  ]) || loopspaceRuntimeField(event?.details, [
    "node_id",
    "loop_runtime_node_id",
  ]);
}

function loopspaceRuntimeEventRunId(event) {
  return loopspaceRuntimeField(event, [
    "run_id",
    "loop_runtime_run_id",
  ]) || loopspaceRuntimeField(event?.details, [
    "run_id",
    "loop_runtime_run_id",
  ]);
}

function loopspaceRuntimeEventEdgeId(event) {
  return loopspaceRuntimeField(event, [
    "edge_id",
    "loop_runtime_edge_id",
  ]) || loopspaceRuntimeField(event?.details, [
    "edge_id",
    "loop_runtime_edge_id",
  ]);
}

function loopspaceRuntimeEventStatus(event) {
  const roots = [
    event,
    event?.details,
    event?.result,
    event?.payload,
    event?.details?.result,
    event?.details?.payload,
    event?.details?.details,
    event?.details?.details?.result,
  ];
  for (const root of roots) {
    if (!root || typeof root !== "object" || Array.isArray(root)) continue;
    const status = normalizeLoopspaceNodeRuntimeStatus(
      root.parent_status || root.status || root.state || root.run_status,
    );
    if (status) return status;
  }
  return "";
}

function loopspaceRuntimeEventStatusLabel(event, fallback = "Runtime event", options = {}) {
  const rawStatus = loopspaceRuntimeField(event, ["status", "state", "run_status"])
    || loopspaceRuntimeField(event?.details, ["status", "state", "parent_status"])
    || "";
  const rawLabel = String(rawStatus || "")
    .trim()
    .replace(/[._-]+/g, " ")
    .replace(/\s+/g, " ");
  if (options.preferRaw && rawLabel) return rawLabel;
  const normalized = loopspaceRuntimeEventStatus(event);
  const normalizedLabel = loopspaceNodeRuntimeStatusLabel(normalized);
  if (normalizedLabel) return normalizedLabel;
  return rawLabel || String(loopspaceRuntimeField(event, ["kind", "event_kind"]) || fallback)
    .trim()
    .replace(/[._-]+/g, " ")
    .replace(/\s+/g, " ");
}

function loopspaceRuntimeEventSortValue(event) {
  const eventSeq = Number(event?.event_seq || event?.seq || 0) || 0;
  const createdAtMs = Number(event?.created_at_ms || event?.ts_ms || 0) || 0;
  return (eventSeq * 10000000000000) + createdAtMs;
}

function loopspaceRuntimeTimestampMs(row) {
  const candidates = [
    row?.updated_at_ms,
    row?.created_at_ms,
    row?.ts_ms,
    row?.updated_at,
    row?.created_at,
  ];
  for (const candidate of candidates) {
    if (typeof candidate === "number" && Number.isFinite(candidate) && candidate > 0) {
      return candidate;
    }
    if (typeof candidate === "string" && candidate.trim()) {
      const numeric = Number(candidate);
      if (Number.isFinite(numeric) && numeric > 0) return numeric;
      const parsed = Date.parse(candidate);
      if (Number.isFinite(parsed) && parsed > 0) return parsed;
    }
  }
  return 0;
}

function buildLoopspaceNodeRuntimeStateMap(events, runtimeHead) {
  const byNodeId = new Map();
  for (const event of jsonArray(events)) {
    const nodeId = loopspaceRuntimeEventNodeId(event);
    const status = loopspaceRuntimeEventStatus(event);
    if (!nodeId || !status) continue;
    const sortValue = loopspaceRuntimeEventSortValue(event);
    const previous = byNodeId.get(nodeId);
    if (previous && previous.sortValue > sortValue) continue;
    byNodeId.set(nodeId, {
      details: event?.details && typeof event.details === "object" ? event.details : {},
      edge_id: loopspaceRuntimeEventEdgeId(event),
      event,
      label: loopspaceNodeRuntimeStatusLabel(status),
      run_id: loopspaceRuntimeEventRunId(event),
      sortValue,
      status,
      tone: loopspaceNodeRuntimeStatusTone(status),
    });
  }
  const headNodeId = loopspaceRuntimeField(runtimeHead, [
    "cursor_node_id",
    "current_node_id",
    "node_id",
    "loop_runtime_node_id",
  ]);
  const headStatus = normalizeLoopspaceNodeRuntimeStatus(loopspaceRuntimeField(runtimeHead, ["status"]));
  if (headNodeId && headStatus) {
    const sortValue = Math.max(
      loopspaceRuntimeEventSortValue(runtimeHead),
      byNodeId.get(headNodeId)?.sortValue || 0,
    ) + 1;
    byNodeId.set(headNodeId, {
      details: runtimeHead?.details && typeof runtimeHead.details === "object" ? runtimeHead.details : {},
      edge_id: loopspaceRuntimeField(runtimeHead, ["edge_id", "loop_runtime_edge_id"]),
      event: runtimeHead,
      label: loopspaceNodeRuntimeStatusLabel(headStatus),
      run_id: loopspaceRuntimeField(runtimeHead, ["run_id", "id", "loop_runtime_run_id"]),
      sortValue,
      status: headStatus,
      tone: loopspaceNodeRuntimeStatusTone(headStatus),
    });
  }
  return byNodeId;
}

function loopspaceRuntimeStateCanResume(state) {
  const status = normalizeLoopspaceNodeRuntimeStatus(state?.status);
  return status === "resume_ready" || status === "interrupted";
}

function loopspaceRuntimeResumeField(state, keys, fallback = "") {
  const roots = [
    state,
    state?.details,
    state?.details?.details,
    state?.details?.resume_context,
    state?.event,
    state?.event?.details,
    state?.event?.details?.details,
    state?.event?.details?.resume_context,
    state?.event?.details?.details?.resume_context,
  ];
  for (const root of roots) {
    if (!root || typeof root !== "object" || Array.isArray(root)) continue;
    for (const key of keys) {
      const value = root[key];
      if (typeof value === "string" && value.trim()) return value.trim();
      if (typeof value === "number" && Number.isFinite(value)) return String(value);
    }
  }
  return fallback;
}

function loopspaceRuntimeResumeCheckpointPlan(state) {
  const roots = [
    state?.details,
    state?.details?.details,
    state?.details?.resume_context,
    state?.event?.details,
    state?.event?.details?.details,
    state?.event?.details?.resume_context,
    state?.event?.details?.details?.resume_context,
  ];
  for (const root of roots) {
    if (!root || typeof root !== "object" || Array.isArray(root)) continue;
    const plan = root.checkpoint_plan;
    if (Array.isArray(plan) && plan.length) {
      return loopspaceGraphCheckpointPlanFromDispatch(plan);
    }
  }
  return [];
}

function buildLoopspaceSendMessageResumePrompt({
  checkpoint_plan: checkpointPlan = [],
  completedCheckpoints = [],
  loop_runtime_edge_id: loopRuntimeEdgeId = "",
  loop_runtime_node_id: loopRuntimeNodeId = "",
  loop_runtime_run_id: loopRuntimeRunId = "",
  loopspace_id: loopspaceId = "",
  nextCheckpoints = [],
  originalPrompt = "",
  trigger_id: triggerId = "",
  trigger_run_id: triggerRunId = "",
} = {}) {
  const completedLines = completedCheckpoints.length
    ? completedCheckpoints.map((checkpoint) => `- ${checkpoint.index}. ${checkpoint.label}`).join("\n")
    : "- None recorded.";
  const nextLines = nextCheckpoints.length
    ? nextCheckpoints.map((checkpoint) => `- ${checkpoint.index}. ${checkpoint.label}`).join("\n")
    : "- Continue from the next unfinished checkpoint you can infer from the terminal state.";
  const allLines = checkpointPlan.length
    ? checkpointPlan.map((checkpoint) => `- ${checkpoint.index}. ${checkpoint.label} [step_id: ${checkpoint.id || "unknown"}]`).join("\n")
    : "- No explicit checkpoint plan was available.";
  return [
    "Resume the interrupted Diff Forge Loopspace send-message run.",
    "",
    "Diff Forge resume context:",
    `- loopspace_id=${loopspaceId || "unknown"}`,
    `- loop_runtime_run_id=${loopRuntimeRunId || "unknown"}`,
    `- loop_runtime_node_id=${loopRuntimeNodeId || "unknown"}`,
    `- loop_runtime_edge_id=${loopRuntimeEdgeId || "unknown"}`,
    ...(triggerId ? [`- trigger_id=${triggerId}`] : []),
    ...(triggerRunId ? [`- trigger_run_id=${triggerRunId}`] : []),
    "Rules:",
    "- Continue this same run. Do not restart the loop from checkpoint 1 unless the terminal state clearly requires it.",
    "- Keep using record_loopspace_step_progress for checkpoint status updates with the ids above.",
    "- Treat completed checkpoints as already done; only revisit them if you need to verify current state.",
    "Completed checkpoints:",
    completedLines,
    "Continue with:",
    nextLines,
    "Full checkpoint plan:",
    allLines,
    "Original message:",
    originalPrompt.trim() || "(Use the visible terminal state and checkpoint plan as the source of truth.)",
  ].join("\n");
}

function normalizeLoopspaceCheckpointProgressStatus(status) {
  const normalized = String(status || "").trim().toLowerCase().replace(/[\s-]+/g, "_");
  if (["complete", "completed", "done", "success", "succeeded"].includes(normalized)) return "completed";
  if (["active", "processing", "running", "started", "working"].includes(normalized)) return "running";
  if (["failed", "failure", "error", "blocked"].includes(normalized)) return "failed";
  if (["skip", "skipped"].includes(normalized)) return "skipped";
  return "";
}

function loopspaceCheckpointProgressFromRuntimeEvent(event) {
  const roots = [
    event,
    event?.payload,
    event?.result,
    event?.details,
    event?.details?.details,
    event?.details?.result,
    event?.details?.payload,
    event?.details?.details?.details,
    event?.details?.details?.result,
    event?.details?.details?.payload,
  ];
  for (const root of roots) {
    if (!root || typeof root !== "object" || Array.isArray(root)) {
      continue;
    }
    const progress = root.checkpoint_progress;
    if (progress && typeof progress === "object" && !Array.isArray(progress)) {
      return progress;
    }
  }
  return null;
}

function loopspaceCheckpointProgressKeys(progress) {
  if (!progress || typeof progress !== "object") {
    return [];
  }
  const keys = [];
  const stepId = appControlText(progress, ["step_id", "checkpoint_id", "id"]);
  if (stepId) {
    keys.push(`id:${stepId}`);
  }
  const stepIndex = Number.parseInt(
    progress.step_index ?? progress.step_ordinal ?? progress.index ?? 0,
    10,
  );
  if (Number.isFinite(stepIndex) && stepIndex > 0) {
    keys.push(`index:${stepIndex}`);
  }
  return keys;
}

function buildLoopspaceCheckpointProgressMap(events, runId, nodeId) {
  const map = new Map();
  const safeRunId = String(runId || "").trim();
  const safeNodeId = String(nodeId || "").trim();
  for (const event of jsonArray(events)) {
    const eventRunId = loopspaceRuntimeEventRunId(event);
    if (safeRunId && eventRunId && eventRunId !== safeRunId) {
      continue;
    }
    const eventNodeId = loopspaceRuntimeEventNodeId(event);
    if (safeNodeId && eventNodeId && eventNodeId !== safeNodeId) {
      continue;
    }
    const progress = loopspaceCheckpointProgressFromRuntimeEvent(event);
    const status = normalizeLoopspaceCheckpointProgressStatus(progress?.status);
    if (!progress || !status) {
      continue;
    }
    for (const key of loopspaceCheckpointProgressKeys(progress)) {
      map.set(key, { progress, status });
    }
  }
  return map;
}

function loopspaceCheckpointProgressValueForNode(node, oneBasedIndex, progressMap) {
  const nodeId = String(node?.id || "").trim();
  if (nodeId && progressMap?.has(`id:${nodeId}`)) {
    return progressMap.get(`id:${nodeId}`);
  }
  if (Number.isFinite(oneBasedIndex) && progressMap?.has(`index:${oneBasedIndex}`)) {
    return progressMap.get(`index:${oneBasedIndex}`);
  }
  return null;
}

function loopspaceCheckpointStatusForNode(node, oneBasedIndex, progressMap) {
  const value = loopspaceCheckpointProgressValueForNode(node, oneBasedIndex, progressMap);
  if (typeof value === "string") {
    return value;
  }
  if (value && typeof value === "object") {
    return normalizeLoopspaceCheckpointProgressStatus(value.status || value.progress?.status);
  }
  return "";
}

function loopspaceCheckpointProgressForNode(node, oneBasedIndex, progressMap) {
  const value = loopspaceCheckpointProgressValueForNode(node, oneBasedIndex, progressMap);
  if (value?.progress && typeof value.progress === "object") {
    return value.progress;
  }
  return value && typeof value === "object" ? value : null;
}

function loopspaceCheckpointProgressAssetIds(progress) {
  if (!progress || typeof progress !== "object") {
    return [];
  }
  const ids = [
    ...safeCloudMcpArray(progress.asset_ids),
    ...safeCloudMcpArray(progress.produced_asset_ids),
    ...safeCloudMcpArray(progress.assets || progress.produced_assets)
      .map((asset) => (
        asset && typeof asset === "object"
          ? appControlText(asset, ["asset_id", "id"])
          : String(asset || "")
      )),
  ].map((id) => String(id || "").trim()).filter(Boolean);
  return ids.filter((id, index) => ids.indexOf(id) === index);
}

function appShellIsMacPlatform() {
  if (typeof navigator === "undefined") {
    return false;
  }

  return /mac|iphone|ipad|ipod/iu.test(navigator.platform || "");
}

function permissionRowTone(known, ready) {
  if (!known) {
    return "neutral";
  }

  return ready ? "ready" : "attention";
}

function permissionStatusLabel(known, ready, readyLabel = "Ready", attentionLabel = "Needs access") {
  if (!known) {
    return "Check";
  }

  return ready ? readyLabel : attentionLabel;
}

function normalizeRemoteCommandName(value) {
  return String(value || "").trim().toLowerCase().replace(/[.\s-]+/g, "_");
}

function normalizeWorkspaceWebTabSessionUrl(value) {
  return normalizeWebInput(value) || String(value || "").trim() || DEFAULT_WEB_URL;
}

function isWorkspaceWebTabPaneId(value) {
  return String(value || "").trim().startsWith("workspace-web-tab-");
}

function findWorkspaceWebTabPaneIdByLabel(sessions, label) {
  const safeLabel = String(label || "").trim();
  if (!safeLabel || !sessions || typeof sessions !== "object") {
    return "";
  }
  return Object.entries(sessions).find(([, session]) => (
    String(session?.popoutLabel || session?.label || "").trim() === safeLabel
  ))?.[0] || "";
}

function normalizeWorkspaceTabId(value) {
  const normalized = normalizeRemoteCommandName(value);
  if (normalized === "terminal" || normalized === "term") {
    return "terminals";
  }
  if (normalized === "file" || normalized === "workspace_files") {
    return "files";
  }
  if (normalized === "doc" || normalized === "docs" || normalized === "document" || normalized === "workspace_docs" || normalized === "workspace_documents") {
    return DEFAULT_WORKSPACE_VIEW;
  }
  if (normalized === "browser" || normalized === "workspace_web" || normalized === "workspace_browser") {
    return "web";
  }
  if (normalized === "histories" || normalized === "task_history" || normalized === "todo_history") {
    return "history";
  }
  return WORKSPACE_TAB_IDS.has(normalized) ? normalized : "";
}

function normalizeAccountAppViewId(value) {
  const normalized = normalizeRemoteCommandName(value);
  if (normalized === "tool" || normalized === "architectures" || normalized === "architecture_tools") {
    return "tools";
  }
  if (normalized === "asset") {
    return "assets";
  }
  if (normalized === "snippet" || normalized === "snippets" || normalized === "voice_snippets") {
    return "audio";
  }
  if (normalized === "snip" || normalized === "snips" || normalized === "screenshot" || normalized === "screenshots") {
    return "snipping";
  }
  if (normalized === "audio_settings" || normalized === "voice" || normalized === "microphone") {
    return "audio";
  }
  if (normalized === "token" || normalized === "tokens" || normalized === "credits") {
    return "tokenomics";
  }
  if (normalized === "setting" || normalized === "preferences") {
    return "settings";
  }
  return ACCOUNT_APP_VIEW_IDS.has(normalized) ? normalized : "";
}

function normalizeAppControlTabId(value) {
  const normalized = normalizeRemoteCommandName(value);
  if (!normalized) {
    return null;
  }
  if (normalized === "orchestrator" || normalized === "orch" || normalized === "terminal_orchestrator" || normalized === "workspace_orchestrator") {
    return {
      id: "orchestrator",
      scope: "workspace-tool",
      view: DEFAULT_WORKSPACE_VIEW,
      workspaceTool: "orchestrator",
    };
  }
  if (normalized === "tool_docs" || normalized === "tools_docs" || normalized === "workspace_tool_docs" || normalized === "docs_panel" || normalized === "documents_panel") {
    return {
      id: "tools",
      scope: "workspace-tool",
      view: DEFAULT_WORKSPACE_VIEW,
      workspaceTool: "tools",
    };
  }
  if (normalized === "tool_tokenomics" || normalized === "workspace_tool_tokenomics" || normalized === "orchestrator_tokenomics") {
    return {
      id: "tokenomics",
      scope: "workspace-tool",
      view: DEFAULT_WORKSPACE_VIEW,
      workspaceTool: "tokenomics",
    };
  }
  if (normalized === "trigger" || normalized === "triggers" || normalized === "loopspace_trigger" || normalized === "loopspace_triggers") {
    return {
      id: "triggers",
      scope: "workspace-tool",
      view: DEFAULT_WORKSPACE_VIEW,
      requiredSpaceMode: "loopspaces",
      workspaceTool: "triggers",
    };
  }
  const workspaceTab = normalizeWorkspaceTabId(normalized);
  if (workspaceTab) {
    return {
      id: workspaceTab,
      scope: "workspace",
      view: WORKSPACE_TAB_VIEW_BY_ID[workspaceTab] || DEFAULT_WORKSPACE_VIEW,
    };
  }
  if (normalized === "architecture" || normalized === "workspace_architecture") {
    return { id: "history", scope: "workspace", view: "architecture" };
  }
  if (normalized === "architectures" || normalized === "architecture_hub") {
    return { id: "architectures", scope: "global", view: "architectures" };
  }
  if (normalized === "mcp" || normalized === "mcps" || normalized === "mcp_servers") {
    return { id: "mcps", scope: "global", view: "mcps" };
  }
  if (normalized === "cli" || normalized === "clis") {
    return { id: "clis", scope: "global", view: "clis" };
  }
  if (normalized === "script" || normalized === "scripts" || normalized === "local_scripts") {
    return { id: "scripts", scope: "global", view: "scripts" };
  }
  if (normalized === "tool" || normalized === "tools") {
    return { id: "tools", scope: "global", view: "tools" };
  }
  const appView = normalizeAccountAppViewId(normalized);
  if (appView) {
    return { id: appView, scope: "global", view: appView };
  }
  return null;
}

const ACCOUNT_WORKSPACE_TOOL_TAB_IDS = new Set(["orchestrator", "tools", "tokenomics"]);
const SELECTED_WORKSPACE_TOOL_TAB_IDS = new Set(["plans", "git"]);
const LOOPSPACE_WORKSPACE_TOOL_TAB_IDS = new Set(["triggers"]);

function appShellWorkspaceToolTabAvailable(tab, { hasWorkspace = false, loopspacesMode = false } = {}) {
  const workspaceTool = String(tab?.workspaceTool || "").trim();
  if (!workspaceTool) {
    return false;
  }
  if (ACCOUNT_WORKSPACE_TOOL_TAB_IDS.has(workspaceTool)) {
    return true;
  }
  if (SELECTED_WORKSPACE_TOOL_TAB_IDS.has(workspaceTool)) {
    return Boolean(hasWorkspace);
  }
  if (LOOPSPACE_WORKSPACE_TOOL_TAB_IDS.has(workspaceTool)) {
    return Boolean(loopspacesMode || tab?.requiredSpaceMode === "loopspaces");
  }
  return false;
}

function workspaceGitPullPromptCheckKey(workspaceId, rootDirectory) {
  if (!workspaceId || !rootDirectory) {
    return "";
  }
  return `${workspaceId}:${getWorkspaceRootIdentity(rootDirectory)}`;
}

const WORKSPACE_GIT_REPOSITORY_PRELOAD_TIMEOUT_MS = 12000;
const WORKSPACE_GIT_REPOSITORY_PRELOAD_LOADING_STALE_MS = 15000;

function workspaceGitRepositoryPreloadLoadingFresh(preload, nowMs = Date.now()) {
  if (!preload || preload.state !== "loading") {
    return false;
  }
  const requestedAtMs = Number(preload.requestedAtMs || preload.generated_at_ms) || 0;
  return requestedAtMs > 0
    && nowMs - requestedAtMs < WORKSPACE_GIT_REPOSITORY_PRELOAD_LOADING_STALE_MS;
}

function normalizeWorkspaceGitPullRepository(repository) {
  const path = String(repository?.path || "").trim();
  const name = String(repository?.name || "").trim() || getDirectoryName(path) || "repository";
  const relativePath = String(repository?.relative_path || "").trim();
  const statusCounts = repository?.status_counts && typeof repository.status_counts === "object"
    ? repository.status_counts
    : {};
  return {
    path,
    name,
    relative_path: relativePath,
    branch: String(repository?.branch || "").trim(),
    head_sha: String(repository?.head_sha || "").trim(),
    upstream: String(repository?.upstream || "").trim(),
    ahead: Number(repository?.ahead) || 0,
    behind: Number(repository?.behind) || 0,
    dirty: Boolean(repository?.dirty),
    status_counts: statusCounts,
    operation_state: repository?.operation_state || null,
    fetch_ok: Boolean(repository?.fetch_ok),
    fetch_error: String(repository?.fetch_error || "").trim(),
    fetch_skipped: Boolean(repository?.fetch_skipped),
    reason: String(repository?.reason || "").trim(),
    pullable: Boolean(repository?.pullable),
  };
}

function readDismissedLowCreditWarningKey() {
  try {
    return window.localStorage.getItem(LOW_CREDIT_WARNING_STORAGE_KEY) || "";
  } catch {
    return "";
  }
}

function writeDismissedLowCreditWarningKey(value) {
  try {
    if (value) {
      window.localStorage.setItem(LOW_CREDIT_WARNING_STORAGE_KEY, value);
    } else {
      window.localStorage.removeItem(LOW_CREDIT_WARNING_STORAGE_KEY);
    }
  } catch {
    // Dismissal is a convenience only.
  }
}

function formatCreditCount(value) {
  const numericValue = Number(value);

  if (!Number.isFinite(numericValue)) {
    return "-";
  }

  return Math.max(0, Math.round(numericValue)).toLocaleString();
}

function creditResetLabel(resetAt) {
  if (!resetAt) {
    return "No reset date";
  }

  try {
    return new Intl.DateTimeFormat(undefined, {
      month: "short",
      day: "numeric",
    }).format(new Date(resetAt));
  } catch {
    return "No reset date";
  }
}

function creditUsagePercent(credits) {
  const total = Number(credits?.termTotalCredits ?? credits?.term_total_credits ?? 0);
  const remaining = creditRemainingWithReserved(credits);

  if (!Number.isFinite(total) || total <= 0) {
    return 0;
  }

  return Math.min(100, Math.max(0, Math.round((remaining / total) * 100)));
}

function liveCreditText(value, fallback = "") {
  const text = String(value ?? "").trim();
  return text || fallback;
}

function liveCreditObject(value) {
  return value && typeof value === "object" && !Array.isArray(value) ? value : null;
}

function billingAccountKey(value) {
  return String(value || "").trim();
}

function billingAccountIdentityToken(value) {
  return billingAccountKey(value);
}

function cloudAccountIdentityToken(value) {
  const cleaned = billingAccountKey(value)
    .split("")
    .map((character) => (
      /[A-Za-z0-9._-]/.test(character) ? character : "_"
    ))
    .join("")
    .replace(/^[._-]+|[._-]+$/g, "")
    .slice(0, 96);
  return cleaned || "";
}

function billingAccountAliasTokens(accountKey, user) {
  const appwriteUserId = billingAccountIdentityToken(
    user?.appwriteUserId || user?.appwrite_user_id,
  );
  const values = [
    accountKey,
    user?.id,
    user?.$id,
    user?.email,
    appwriteUserId,
  ];
  if (appwriteUserId) {
    values.push(
      `user:${appwriteUserId}`,
      cloudAccountIdentityToken(`user:${appwriteUserId}`),
    );
  }
  return new Set(values.map(billingAccountIdentityToken).filter(Boolean));
}

function accountUsageIdentityTokens(payload, snapshot) {
  const object = liveCreditObject(payload) || {};
  const roots = [
    object,
    liveCreditObject(object.envelope),
    liveCreditObject(object.snapshot),
    liveCreditObject(object.payload),
    liveCreditObject(object.data),
    liveCreditObject(object.payload?.snapshot),
    liveCreditObject(object.data?.snapshot),
    liveCreditObject(snapshot),
  ].filter(Boolean);
  const tokens = new Set();
  for (const root of roots) {
    for (const key of [
      "accountKey",
      "account_key",
      "accountId",
      "account_id",
      "desktopAccountKey",
      "desktop_account_key",
      "scopeKey",
      "scope_key",
    ]) {
      const token = billingAccountIdentityToken(root?.[key]);
      if (token) {
        tokens.add(token);
      }
    }
  }
  return tokens;
}

function accountUsageMatchesCurrentAccount(payload, snapshot, currentAliases) {
  const eventAccounts = accountUsageIdentityTokens(payload, snapshot);
  if (!eventAccounts.size) {
    // Untagged events cannot be attributed safely after an account switch.
    // The account-bound billing poll remains the compatibility fallback.
    return false;
  }
  if (!currentAliases?.size) {
    return false;
  }
  return [...eventAccounts].some((token) => currentAliases.has(token));
}

function liveCreditHasMeaningfulSnapshot(credits) {
  return creditSnapshotHasMeaningfulData(credits);
}

function normalizeLiveCreditWallet(wallet, previous = {}, options = {}) {
  return normalizeCreditWallet(wallet, previous, options);
}

function liveCreditEventKind(value) {
  return String(value?.kind || value?.event_kind || "").trim();
}

function liveCreditSnapshotIsAuthoritative(wallet, snapshot = {}) {
  const object = liveCreditObject(liveCreditObject(wallet)?.credits)
    || liveCreditObject(liveCreditObject(wallet)?.wallet)
    || liveCreditObject(wallet);
  if (!object) return false;
  if (object.known === false && object.live !== true) return false;
  const eventKind = liveCreditEventKind(snapshot);
  return snapshot?.contract === "diffforge.account_usage.v1"
    || eventKind === "account_usage_snapshot"
    || eventKind.startsWith("credit_wallet_")
    || object.known === true
    || object.live === true;
}

function billingStatusHasMeaningfulData(status) {
  const object = liveCreditObject(status);
  if (!object) return false;
  return Boolean(
    billingStatusPlanName(object)
      || billingStatusPlanStatus(object)
      || liveCreditHasMeaningfulSnapshot(billingStatusCredits(object))
  );
}

function mergeBillingStatusSnapshot(previous, incoming, options = {}) {
  if (!billingStatusHasMeaningfulData(incoming)) {
    return previous || null;
  }
  const previousCredits = billingStatusCredits(previous);
  const candidateIncomingCredits = billingStatusCredits(incoming);
  const incomingCredits = liveCreditHasMeaningfulSnapshot(candidateIncomingCredits)
    ? candidateIncomingCredits
    : null;
  const next = {
    ...(previous || {}),
    ...(incoming || {}),
  };
  if (incomingCredits) {
    next.credits = normalizeLiveCreditWallet(incomingCredits, previousCredits, {
      preferIncomingTotals: Boolean(options?.preferIncomingCredits),
    }) || incomingCredits;
  } else if (previousCredits && liveCreditHasMeaningfulSnapshot(previousCredits)) {
    next.credits = previousCredits;
  }
  if (next.user && typeof next.user === "object" && !Array.isArray(next.user)) {
    next.user = {
      ...next.user,
      credits: next.credits || next.user.credits,
    };
  }
  // Object spread can leave a stale camel alias beside a fresher snake alias
  // (or vice versa). Resolve from the incoming snapshot first, then stamp both
  // spellings so later camel-first readers cannot select the stale value.
  const planName = billingStatusPlanName(incoming) || billingStatusPlanName(previous);
  const planStatus = billingStatusPlanStatus(incoming) || billingStatusPlanStatus(previous);
  const updatedAt = billingStatusUpdatedAt(incoming) || billingStatusUpdatedAt(previous);
  if (planName) {
    next.planName = planName;
    next.plan_name = planName;
  }
  if (planStatus) {
    next.planStatus = planStatus;
    next.plan_status = planStatus;
  }
  if (updatedAt) {
    next.updatedAt = updatedAt;
    next.updated_at = updatedAt;
  }
  return next;
}

function lowCreditWarningKey(credits) {
  if (!credits) {
    return "";
  }

  return [
    credits.termId || credits.term_id || credits.resetAt || credits.reset_at || "current",
    credits.lowCreditState || credits.low_credit_state || "unknown",
    String(creditRemainingWithReserved(credits)),
  ].join(":");
}

function shouldShowLowCreditWarning(credits, dismissedKey) {
  if (!credits) {
    return false;
  }

  const state = String(credits.lowCreditState || credits.low_credit_state || "").toLowerCase();
  const remaining = creditRemainingWithReserved(credits);
  const isLow = ["low", "critical", "exhausted", "missing_term"].includes(state)
    || (Number.isFinite(remaining) && remaining <= LOW_CREDIT_WARNING_THRESHOLD);
  const warningKey = lowCreditWarningKey(credits);

  return Boolean(isLow && warningKey && warningKey !== dismissedKey);
}

function lowCreditWarningCloudSynced(syncStatus, liveSyncEpoch) {
  if (!syncStatus || !liveSyncEpoch) {
    return false;
  }

  const connection = String(syncStatus.connection || "").toLowerCase();
  if (connection !== "connected") {
    return false;
  }

  const sizeClass = String(syncStatus.size_class || "live").toLowerCase();
  const syncing = Boolean(syncStatus.syncing) || sizeClass === "large";
  const pendingCount = normalizeCloudSyncCount(syncStatus.pending_count);
  const upCount = normalizeCloudSyncCount(syncStatus.up_count ?? pendingCount);
  const downCount = normalizeCloudSyncCount(syncStatus.down_count);
  const controlCount = normalizeCloudSyncCount(syncStatus.control_count);

  return !syncing && pendingCount === 0 && upCount === 0 && downCount === 0 && controlCount === 0;
}

async function recordCloudSigninDiagnostic() {
  return undefined;
}

async function recordCloudConnectionDiagnostic() {
  return undefined;
}

async function refreshCloudMcpSessionContext(options = {}) {
  const expectedAccountKey = billingAccountKey(options.expectedAccountKey);
  const expectedAuthAuthorityVersion = Number(options.expectedAuthAuthorityVersion);
  const assertExpectedAccount = () => {
    if (
      expectedAccountKey
      && billingAccountKey(authStore.getSnapshot()?.accountKey) !== expectedAccountKey
    ) {
      const error = new Error("Cloud context refresh belongs to a previous account.");
      error.code = "STALE_AUTH_ACCOUNT";
      throw error;
    }
    if (
      Number.isFinite(expectedAuthAuthorityVersion)
      && authStore.getAuthorityVersion() !== expectedAuthAuthorityVersion
    ) {
      const error = new Error("Cloud context refresh belongs to a previous auth session.");
      error.code = "STALE_AUTH_ACCOUNT";
      throw error;
    }
  };
  const emitProgress = (progress) => {
    if (typeof options.onProgress !== "function") {
      return;
    }

    try {
      options.onProgress(progress);
    } catch {
      // Progress callbacks are visual only.
    }
  };

  try {
    const flowId = options.flowId || "desktop-cloud-connect";
    assertExpectedAccount();
    emitProgress({
      detail: "Refreshing your signed-in cloud context in the native runtime.",
      stage: "desktop_session",
      status: "active",
      title: "Preparing cloud workspace",
    });
    await recordCloudConnectionDiagnostic({
      channel: "rust-client-auth",
      flowId,
      step: "rust.cloud_mcp.context.refresh",
      status: "start",
      message: "Rust client is refreshing native Cloud MCP auth context.",
      details: {
        requireConnected: Boolean(options.requireConnected),
      },
    });
    assertExpectedAccount();
    await recordCloudSigninDiagnostic({
      flowId,
      step: "cloud_mcp.context.refresh",
      status: "start",
      message: "refreshing Cloud MCP auth context",
      details: {
        requireConnected: Boolean(options.requireConnected),
      },
    });
    assertExpectedAccount();
    if (options.accountScope) {
      assertExpectedAccount();
      await authStore.setActiveScope(options.accountScope);
      assertExpectedAccount();
    }
    if (options.billing_status && expectedAccountKey) {
      assertExpectedAccount();
      await authStore.applyBillingStatus(options.billing_status, {
        expectedAccountKey,
      });
      assertExpectedAccount();
    }
    const status = await invoke("cloud_mcp_get_status");
    assertExpectedAccount();
    await recordCloudConnectionDiagnostic({
      channel: "rust-client-auth",
      flowId,
      step: "rust.cloud_mcp.context.refresh",
      status: "ok",
      message: "Cloud MCP runtime context refresh completed.",
      details: status,
    });
    assertExpectedAccount();
    await recordCloudSigninDiagnostic({
      flowId,
      step: "cloud_mcp.context.refresh",
      status: "ok",
      message: "Cloud MCP runtime context refresh completed",
      details: status,
    });
    assertExpectedAccount();

    emitProgress({
      detail: "The native runtime is using your signed-in cloud context.",
      stage: "desktop_session",
      status: "complete",
      title: "Cloud context ready",
    });

    if (!options.requireConnected) {
      return status;
    }

    const connectAttempts = Math.max(1, Math.floor(Number(options.connectAttempts || 1)));
    const retryDelayMs = Math.max(0, Number(options.connectRetryDelayMs || 0));
    let lastConnectError = null;

    for (let attempt = 1; attempt <= connectAttempts; attempt += 1) {
      assertExpectedAccount();
      emitProgress({
        attempt,
        detail: attempt === 1
          ? "Preparing short-lived cloud auth and requesting the assigned workspace route."
          : `The workspace is still coming online. Retrying connection ${attempt} of ${connectAttempts}.`,
        stage: attempt === 1 ? "cloud_auth" : "cloud_instance",
        status: "active",
        title: attempt === 1 ? "Preparing cloud auth" : "Still setting up your instance",
      });
      await recordCloudSigninDiagnostic({
        flowId,
        step: "cloud_mcp.connect.invoke",
        status: "start",
        message: "requesting Cloud MCP websocket connection",
        details: {
          attempt,
          attempts: connectAttempts,
          timeout_ms: CLOUD_MCP_AUTH_CONNECT_TIMEOUT_MS,
        },
      });
      assertExpectedAccount();

      const stopStatusPolling = startCloudWorkspaceStatusPolling(emitProgress);
      try {
        const connectedStatus = await withTimeout(
          invoke("cloud_mcp_connect", {
            expected_account_key: expectedAccountKey || null,
          }),
          CLOUD_MCP_AUTH_CONNECT_TIMEOUT_MS,
          CLOUD_MCP_AUTH_CONNECT_TIMEOUT_MESSAGE,
        );
        assertExpectedAccount();
        stopStatusPolling();
        await recordCloudConnectionDiagnostic({
          channel: "rust-client-auth",
          flowId,
          step: "rust.cloud_mcp.connect",
          status: connectedStatus?.connected && connectedStatus?.global_ws_connected ? "ok" : "warn",
          message: "Rust client Cloud MCP websocket connect command returned.",
          details: connectedStatus,
        });
        assertExpectedAccount();
        await recordCloudSigninDiagnostic({
          flowId,
          step: "cloud_mcp.connect.invoke",
          status: "ok",
          message: "Cloud MCP websocket connect command returned",
          details: connectedStatus,
        });
        assertExpectedAccount();

        if (!connectedStatus?.connected || !connectedStatus?.global_ws_connected) {
          throw new Error("Cloud workspace websocket is not connected yet.");
        }

        emitProgress({
          ...cloudWorkspaceProgressFromRuntimeStatus(connectedStatus),
          attempt,
          detail: "Your assigned cloud workspace is live and ready.",
          status: "connected",
          title: "Cloud workspace ready",
        });

        return connectedStatus;
      } catch (connectError) {
        stopStatusPolling();
        if (connectError?.code === "STALE_AUTH_ACCOUNT") {
          throw connectError;
        }
        lastConnectError = connectError;

        if (attempt < connectAttempts) {
          emitProgress({
            attempt,
            detail: "The cloud route is still warming. The desktop app will keep waiting automatically.",
            stage: "cloud_instance",
            status: "active",
            title: "Still setting up your instance",
          });

          if (retryDelayMs > 0) {
            await waitMs(retryDelayMs);
            assertExpectedAccount();
          }
          continue;
        }

        throw connectError;
      }
    }

    throw lastConnectError || new Error("Cloud workspace websocket is not connected yet.");
  } catch (error) {
    if (error?.code === "STALE_AUTH_ACCOUNT") {
      return null;
    }
    if (options.requireConnected) {
      emitProgress({
        detail: getErrorMessage(error, "The cloud workspace did not finish connecting."),
        stage: "workspace_socket",
        status: "error",
        title: "Cloud workspace still unavailable",
      });
      await recordCloudConnectionDiagnostic({
        channel: "rust-client-auth",
        flowId: options.flowId || "desktop-cloud-connect",
        step: "rust.cloud_mcp.connect",
        status: "error",
        message: getErrorMessage(error, "Cloud MCP connection failed."),
        details: { requireConnected: true },
      });
      await recordCloudSigninDiagnostic({
        flowId: options.flowId || "desktop-cloud-connect",
        step: "cloud_mcp.connect.invoke",
        status: "error",
        message: getErrorMessage(error, "Cloud MCP connection failed."),
        details: { requireConnected: true },
      });
      throw error;
    }

    // Cloud MCP retries after the next auth transition.
    return null;
  }
}

function readMainWindowFocusedFallback() {
  if (typeof document === "undefined") {
    return true;
  }
  return document.visibilityState !== "hidden" && document.hasFocus();
}

function readMainWindowRenderableFallback() {
  return getRenderabilitySnapshot().renderable;
}

function scheduleRenderableTimeout(callback, delayMs) {
  let cancelled = false;
  let timer = 0;
  let startedAt = 0;
  let remainingMs = Math.max(0, Number.parseInt(delayMs, 10) || 0);
  let unsubscribe = null;

  const clearTimer = () => {
    if (!timer) {
      return;
    }
    window.clearTimeout(timer);
    timer = 0;
  };

  const cleanup = () => {
    clearTimer();
    if (typeof unsubscribe === "function") {
      unsubscribe();
      unsubscribe = null;
    }
  };

  const arm = () => {
    if (cancelled || timer || !readMainWindowRenderableFallback()) {
      return;
    }
    startedAt = Date.now();
    timer = window.setTimeout(() => {
      timer = 0;
      cleanup();
      if (!cancelled) {
        callback();
      }
    }, remainingMs);
  };

  const pause = () => {
    if (!timer) {
      return;
    }
    remainingMs = Math.max(0, remainingMs - (Date.now() - startedAt));
    clearTimer();
  };

  unsubscribe = subscribeToRenderability((nextSnapshot) => {
    if (nextSnapshot.renderable) {
      arm();
    } else {
      pause();
    }
  });
  arm();

  return () => {
    cancelled = true;
    cleanup();
  };
}

function cancelRenderableTimer(request) {
  if (typeof request?.cancelTimer === "function") {
    request.cancelTimer();
    return;
  }
  if (request?.timer) {
    window.clearTimeout(request.timer);
  }
}

