    const applyScriptEvents = (payloads) => {
      if (disposed || !payloads.length) return;
      setAppScriptRunResults((current) => {
        let next = current;
        for (const payload of payloads) {
          const pathKey = appScriptText(payload.path_key);
          if (!pathKey) continue;
          const runId = appScriptText(payload.run_id);
          const log = appScriptRunLogFromEvent(payload, next[runId] || next[pathKey] || { path_key: pathKey, run_id: runId });
          if (!log) continue;
          const nextRunId = log.run_id || runId;
          next = {
            ...next,
            [pathKey]: log,
            ...(nextRunId ? { [nextRunId]: log } : {}),
          };
        }
        return next;
      });
    };

    const flushPendingOutputs = () => {
      outputFlushTimer = 0;
      const payloads = pendingOutputEvents;
      pendingOutputEvents = [];
      applyScriptEvents(payloads);
    };

