  const recordWorkspaceVisibleTerminalStatus = useCallback((event = {}) => {
    const workspaceId = String(event.workspace_id || "").trim();
    const terminalIndex = Number(event.terminal_index);
    if (!workspaceId || !Number.isInteger(terminalIndex)) {
      return { recorded: false, stale_rejected: false };
    }

    const type = String(event.type || event.event_type || "").trim().toLowerCase();
    const rawStatus = String(
      event.status || event.terminal_status || event.native_rail_state || event.activity_status || type || "",
    ).trim().toLowerCase();
    const key = `${workspaceId}:${terminalIndex}`;
    if (["deleted", "removed", "tombstoned"].includes(type || rawStatus)) {
      if (workspaceVisibleTerminalStatusRef.current.delete(key)) {
        setWorkspaceVisibleTerminalRevision((revision) => revision + 1);
      }
      return { recorded: true, stale_rejected: false };
    }

    const status = rawStatus || "idle";
    const previous = workspaceVisibleTerminalStatusRef.current.get(key) || {};
    if (terminalCanonicalEventIsStale(previous, event)) {
      return { recorded: false, stale_rejected: true };
    }
    const canonicalCohort = terminalCanonicalCohortForInstance(previous, event);
    const next = {
      ...previous,
      ...canonicalCohort,
      activity_status: String(
        event.activity_status || event.native_rail_state || status,
      ).trim(),
      agent_id: String(event.agent_id || event.current_agent || previous.agent_id || "").trim(),
      instance_id: event.instance_id ?? event.terminal_instance_id ?? previous.instance_id ?? "",
      terminal_process_epoch: event.terminal_process_epoch
        ?? event.terminalProcessEpoch
        ?? previous.terminal_process_epoch
        ?? "",
      native_rail_label: String(event.native_rail_label || previous.native_rail_label || "").trim(),
      native_rail_state: String(event.native_rail_state || event.activity_status || status).trim(),
      pane_id: String(event.pane_id || previous.pane_id || "").trim(),
      status,
      terminal_index: terminalIndex,
      thread_id: String(event.thread_id || previous.thread_id || "").trim(),
      type,
      updated_at_ms: Date.now(),
      workspace_id: workspaceId,
    };
    const previousKey = JSON.stringify(previous);
    const nextKey = JSON.stringify(next);
    if (previousKey !== nextKey) {
      workspaceVisibleTerminalStatusRef.current.set(key, next);
      setWorkspaceVisibleTerminalRevision((revision) => revision + 1);
    }
    return { recorded: true, stale_rejected: false };
  }, []);

  useEffect(() => {
    let cancelled = false;
    let retryTimer = 0;
    let retryAttempt = 0;

    const clearRetryTimer = () => {
      if (retryTimer && typeof window !== "undefined") {
        window.clearTimeout(retryTimer);
      }
      retryTimer = 0;
    };

    const scheduleRetry = () => {
      if (cancelled || typeof window === "undefined") {
        return;
      }
      clearRetryTimer();
      const delayMs = CLOUD_DESKTOP_DEVICE_PROFILE_RETRY_DELAYS_MS[
        Math.min(retryAttempt, CLOUD_DESKTOP_DEVICE_PROFILE_RETRY_DELAYS_MS.length - 1)
      ];
      retryTimer = window.setTimeout(() => {
        retryTimer = 0;
        void fetchDesktopDeviceProfile();
      }, delayMs);
      retryAttempt += 1;
    };

    const fetchDesktopDeviceProfile = async () => {
      clearRetryTimer();
      try {
        const profile = await invoke("cloud_mcp_get_desktop_device_profile");
        if (cancelled) {
          return;
        }
        if (!profile || typeof profile !== "object") {
          scheduleRetry();
          return;
        }
        retryAttempt = 0;
        setCloudDesktopDeviceProfile(profile);
      } catch {
        scheduleRetry();
      }
    };

    const refetchOnForeground = () => {
      if (cancelled) {
        return;
      }
      if (typeof document !== "undefined" && document.visibilityState === "hidden") {
        return;
      }
      retryAttempt = 0;
      void fetchDesktopDeviceProfile();
    };

    void fetchDesktopDeviceProfile();
    if (typeof window !== "undefined") {
      window.addEventListener("focus", refetchOnForeground);
    }
    if (typeof document !== "undefined") {
      document.addEventListener("visibilitychange", refetchOnForeground);
    }
    return () => {
      cancelled = true;
      clearRetryTimer();
      if (typeof window !== "undefined") {
        window.removeEventListener("focus", refetchOnForeground);
      }
      if (typeof document !== "undefined") {
        document.removeEventListener("visibilitychange", refetchOnForeground);
      }
    };
  }, []);

