    event?.preventDefault?.();
    event?.stopPropagation?.();

    if (networkingOverlayOpen) {
      setNetworkingOverlayOpen(false);
      return;
    }

    if (workspaceCloseInFlightRef.current) {
      performCloseWindow({ reason: `${reason}_retry` });
      return;
    }

    if (appCloseConfirmStateRef.current.isOpen || appCloseConfirmStateRef.current.isLoading) {
      return;
    }

    const requestGeneratedAtMs = Date.now();
    if (!appHasOpenWorkspaceRuntime()) {
      const confirmation = {
        ...buildEmptyAppCloseTerminalSnapshot(reason, requestGeneratedAtMs),
        isOpen: true,
        isLoading: false,
      };
      appCloseConfirmStateRef.current = confirmation;
      setAppCloseConfirmState(confirmation);
      return;
    }

    const loadingConfirmation = {
      ...APP_CLOSE_CONFIRM_INITIAL_STATE,
      generated_at_ms: requestGeneratedAtMs,
      isOpen: true,
      isLoading: true,
      source: reason,
    };
    appCloseConfirmStateRef.current = loadingConfirmation;
    setAppCloseConfirmState(loadingConfirmation);

    runWindowAction(async () => {
      const closeRequestIsCurrent = () => {
        const currentConfirmation = appCloseConfirmStateRef.current;
        return Boolean(
          currentConfirmation.isLoading
            && currentConfirmation.generated_at_ms === requestGeneratedAtMs,
        );
      };

      try {
        const snapshot = await readAppCloseActiveTerminalSnapshot(reason);
        if (!closeRequestIsCurrent()) {
          return;
        }

        const confirmation = {
          ...snapshot,
          generated_at_ms: requestGeneratedAtMs,
          isOpen: true,
          isLoading: false,
        };
        appCloseConfirmStateRef.current = confirmation;
        setAppCloseConfirmState(confirmation);
      } catch (error) {
        if (!closeRequestIsCurrent()) {
          return;
        }

        const errorConfirmation = {
          ...APP_CLOSE_CONFIRM_INITIAL_STATE,
          error: getErrorMessage(error, "Unable to inspect running terminals before shutdown."),
          generated_at_ms: requestGeneratedAtMs,
          isOpen: true,
          source: reason,
        };
        appCloseConfirmStateRef.current = errorConfirmation;
        setAppCloseConfirmState(errorConfirmation);
      }
    });
