        servers: workspaceMcpServers,
        panel_clear_reason: panelListEmptyAuthoritative ? "no_workspace_panels" : "",
        panel_count: panels.length,
        panels,
        panel_list_empty_authoritative: panelListEmptyAuthoritative,
