        agent_chat_session_id: requested.agent_chat_session_id
          || (sessionRefMatchesAgent ? sessionRef : "")
          || terminalSession.agent_chat_session_id,
        provider_session_id: requested.provider_session_id
          || (sessionRefMatchesProvider ? sessionRef : "")
          || terminalSession.provider_session_id,
