      const requestedProviderSessionId = String(requested.provider_session_id || "").trim();
      const requestedSessionRef = String(sessionRef || "").trim();
      const terminalAgentSessionId = String(terminalSession.agent_chat_session_id || "").trim();
      const terminalProviderSessionId = String(terminalSession.provider_session_id || "").trim();
