      const addedIndexes = new Set(added.map((terminal) => terminal.terminal_index));
      const addedTerminals = after.terminals.filter((terminal) => addedIndexes.has(terminal.terminal_index));
      const shouldFocus = appControlBooleanValue(
        input.focus ?? input.select ?? input.activate,
        true,
      );
      let activated = false;
      let focusTarget = addedTerminals[addedTerminals.length - 1]
