        agentStarted: session.agentStarted === true,
        hasForkFromProviderSessionId: Boolean(session.fork_from_provider_session_id),
        hasProviderSessionId: Boolean(session.provider_session_id),
        instance_id: session.instance_id || "",
        needsAgentStart: session.needsAgentStart === true,
        pane_id: session.pane_id || "",
